        {
            f.RuleFor(x => x.IsComplete, isComplete);
            f.RuleFor(x => x.CompletedAt, completedAt ?? (isComplete ? DateTime.UtcNow : null));
        });

    public TodoItemBuilder WithTodoListId(Guid todoListId) =>
        CloneWith(f => f.RuleFor(x => x.TodoListId, todoListId));

