20	                        Guid.NewGuid().ToString(),
21	                        null,
22	                        $"[INJECT] Random item {rng.Next(1000)}",
23	                        false,
24	                        DateTime.UtcNow,
25	                        DateTime.UtcNow
26	                    );
27	                    list.Items.Add(item);
