using System.Text.Json;
using Microsoft.EntityFrameworkCore;
using TodoApi.Application.ExternalApi;
using TodoApi.Application.ExternalApi.Payloads;
using TodoApi.Application.Sync;
using TodoApi.Data.Entities;
using TodoApi.Infrastructure.Persistence;

namespace TodoApi.Application.Jobs.Strategies;

public sealed class TodoItemCreatedStrategy(
    IExternalTodoApiClient client,
    ITodoListRepositoryQuery lists,
    ISyncMappingRepository mappings,
    ILogger<TodoItemCreatedStrategy> logger
) : ISyncEventStrategy
{
    public bool CanHandle(SyncEvent syncEvent) =>
        syncEvent is { EntityType: EntityType.TodoItem, EventType: EventType.Created };

    public async Task ExecuteAsync(SyncEvent syncEvent, CancellationToken ct)
    {
        ArgumentNullException.ThrowIfNull(syncEvent);

        try
        {
            var payload = JsonSerializer.Deserialize<TodoItemCreatedPayload>(syncEvent.Payload)!;

            var list = await lists
                .GetQueryable()
                .Include(l => l.Items)
                .FirstOrDefaultAsync(l => l.Id == payload.TodoListId, ct)
                .ConfigureAwait(false);

            if (list is null)
            {
                return;
            }

            var request = new CreateExternalTodoListRequest(
                list.Id.ToString(),
                list.Name,
                list.Items
                    .Select(i => new CreateExternalTodoItemRequest(
                        i.Id.ToString(),
                        i.Name,
                        i.IsComplete
                    ))
                    .ToList()
            );

            var result = await client.CreateTodoListAsync(request, ct).ConfigureAwait(false);

            await UpsertListMappingAsync(list.Id, result, ct).ConfigureAwait(false);

            foreach (var externalItem in result.Items)
            {
                await UpsertItemMappingAsync(externalItem, ct).ConfigureAwait(false);
            }
        }
        catch (Exception ex)
        {
            logger.LogTodoItemCreatedStrategyFailed(syncEvent.Id, syncEvent.EntityId, ex);
            throw;
        }
    }

    private async Task UpsertListMappingAsync(Guid localId, ExternalTodoList external, CancellationToken ct)
    {
        var existing = await mappings
            .FindByLocalIdAsync(EntityType.TodoList, localId, ct)
            .ConfigureAwait(false);

        if (existing is not null)
        {
            existing.UpdateSync(external.Id, external.UpdatedAt);
        }
        else
        {
            await mappings
                .AddAsync(new SyncMapping(EntityType.TodoList, localId, external.Id, external.UpdatedAt), ct)
                .ConfigureAwait(false);
        }
    }

    private async Task UpsertItemMappingAsync(ExternalTodoItem external, CancellationToken ct)
    {
        if (!Guid.TryParse(external.SourceId, out var localItemId))
        {
            return;
        }

        var existing = await mappings
            .FindByLocalIdAsync(EntityType.TodoItem, localItemId, ct)
            .ConfigureAwait(false);

        if (existing is not null)
        {
            existing.UpdateSync(external.Id, external.UpdatedAt);
        }
        else
        {
            await mappings
                .AddAsync(new SyncMapping(EntityType.TodoItem, localItemId, external.Id, external.UpdatedAt), ct)
                .ConfigureAwait(false);
        }
    }
}

internal static partial class TodoItemCreatedStrategyLoggerDefinition
{
    [LoggerMessage(
        EventId = 1400,
        Level = LogLevel.Error,
        EventName = "TodoItemCreatedStrategyFailed",
        Message = "TodoItemCreated strategy failed for SyncEventId: {SyncEventId}, EntityId: {EntityId}"
    )]
    public static partial void LogTodoItemCreatedStrategyFailed(
        this ILogger logger,
        Guid syncEventId,
        Guid entityId,
        Exception ex
    );
}

