14	namespace TodoApi.Tests.Application.Jobs;
15	
16	public sealed class OutboundSyncJobCoalesceTests : AsyncLifetimeBase
17	{
18	    private IExternalTodoApiClient _client = null!;
19	    private SyncEventCommandRepository _syncEventRepo = null!;
20	    private SyncMappingCommandRepository _syncMappingRepo = null!;
21	
22	    protected override Task OnInitializeAsync()
23	    {
24	        _client = Substitute.For<IExternalTodoApiClient>();
25	        _syncEventRepo = new SyncEventCommandRepository(Context);
26	        _syncMappingRepo = new SyncMappingCommandRepository(Context);
27	
28	        return Task.CompletedTask;
29	    }
30	
31	    [Fact]
32	    public async Task Handler_WhenTodoListCreated_ShouldEnqueueSyncEvent()
33	    {
34	        // Arrange — use handler to enqueue, then verify event is persisted
35	        var handler = new TodoApi.Application.Commands.CreateTodoList.CreateTodoListHandler(
36	            new TodoListCommandRepository(Context),
37	            _syncEventRepo,
38	            Clock,
39	            NullLogger<TodoApi.Application.Commands.CreateTodoList.CreateTodoListHandler>.Instance
40	        );
41	
42	        var command = new TodoApi.Application.Commands.CreateTodoList.CreateTodoListCommand(
43	            "Test list"
44	        );
45	
46	        // Act
47	        var result = await handler.Handle(command, CancellationToken.None);
48	        await SaveChangesAsync();
49	
50	        // Assert
51	        result.IsSuccess.Should().BeTrue();
52	
53	        var events = await Context.SyncEvent.ToListAsync();
54	        events.Should().HaveCount(1);
55	        events[0].EntityType.Should().Be(EntityType.TodoList);
56	        events[0].EventType.Should().Be(EventType.Created);
57	        events[0].Status.Should().Be(SyncStatus.Pending);
58	    }
59	
60	    [Fact]
61	    public async Task Strategies_WhenDispatched_ShouldCoalesceMultipleEventsForSameEntity()
62	    {
63	        // Arrange — two pending events for the same list entity
64	        var listId = Guid.NewGuid();
65	
66	        var older = new SyncEvent(
67	            EntityType.TodoList,
68	            listId,
69	            EventType.Created,
70	            $"{{\"Id\":\"{listId}\",\"Name\":\"Old\"}}"
71	        );
72	        var newer = new SyncEvent(
73	            EntityType.TodoList,
74	            listId,
75	            EventType.Updated,
76	            $"{{\"Id\":\"{listId}\",\"Name\":\"New\"}}"
77	        );
78	
79	        await _syncEventRepo.AddAsync(older);
80	        await _syncEventRepo.AddAsync(newer);
81	
82	        var listMapping = new SyncMapping(
83	            EntityType.TodoList,
84	            listId,
85	            "ext-list",
86	            DateTime.UtcNow.AddHours(-1)
87	        );
88	        await _syncMappingRepo.AddAsync(listMapping);
89	
90	        await SaveChangesAsync();
91	
92	        var updatedAt = DateTime.UtcNow;
93	        _client
94	            .UpdateTodoListAsync(
95	                Arg.Any<string>(),
96	                Arg.Any<UpdateExternalTodoListRequest>(),
97	                Arg.Any<CancellationToken>()
98	            )
99	            .Returns(new ExternalTodoList("ext-list", "New", updatedAt, []));
100	
101	        var strategies = new ISyncEventStrategy[]
102	        {
103	            new TodoListCreatedStrategy(_client, _syncMappingRepo),
104	            new TodoListUpdatedStrategy(_client, _syncMappingRepo),
105	        };
106	
107	        var dispatcher = new SyncEventDispatcher(strategies);
108	
109	        var pending = await _syncEventRepo.GetPendingAsync(50, CancellationToken.None);
110	
111	        var coalesced = pending
112	            .GroupBy(e => e.EntityId)
113	            .Select(g => g.OrderByDescending(e => e.CreatedAt).First())
114	            .ToList();
115	
116	        coalesced.Should().HaveCount(1);
117	        coalesced[0].EventType.Should().Be(EventType.Updated);
118	
119	        // Act
120	        await dispatcher.DispatchAsync(coalesced[0], CancellationToken.None);
121	        await SaveChangesAsync();
122	
123	        // Assert: only UpdateTodoListAsync was called, not Create
124	        await _client
125	            .Received(1)
126	            .UpdateTodoListAsync(
127	                "ext-list",
128	                Arg.Is<UpdateExternalTodoListRequest>(r => r.Name == "New"),
129	                Arg.Any<CancellationToken>()
130	            );
131	
132	        await _client
133	            .DidNotReceive()
134	            .CreateTodoListAsync(
135	                Arg.Any<CreateExternalTodoListRequest>(),
136	                Arg.Any<CancellationToken>()
137	            );
138	    }
139	}
