    [Fact]
    public void CanHandle_WhenTodoListCreated_ShouldReturnTrue()
    {
        var evt = new SyncEvent(EntityType.TodoList, Guid.NewGuid(), EventType.Created, "{}");
        _strategy.CanHandle(evt).Should().BeTrue();
