    [Fact]
    public async Task ExecuteAsync_WhenMappingExists_ShouldDeleteExternalAndRemoveMapping()
    {
        // Arrange
        var listId = Guid.NewGuid();
        var mapping = new SyncMapping(EntityType.TodoList, listId, "ext-123", DateTime.UtcNow);
